package agent

import (
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/lockmetrics"
)

// LockRetryPolicy describes the retry/backoff curve used when attempting to
// acquire a process-shared lock that guards git index operations on the
// primary .git (the tracker-commit lock). The policy is owned by this
// package per ddx-da11a34a AC#4: callers in cli/internal/triage and
// elsewhere consult ActionRetryWithBackoff but do not duplicate the curve
// implementation here.
//
// The curve is exponential with a cap and a bounded max-retries budget so
// that lock contention is absorbed silently up to a point, after which it
// surfaces as an ordinary error to the caller. Per TD-031 §8.5
// (LockContentionContract) lock contention does NOT change persisted bead
// status; the bead remains claimable and the worker remains `draining`.
type LockRetryPolicy struct {
	// InitialBackoff is the wait before the second attempt.
	InitialBackoff time.Duration
	// MaxBackoff caps the per-step backoff after exponential growth.
	MaxBackoff time.Duration
	// Multiplier is the per-step growth factor (>= 1.0).
	Multiplier float64
	// MaxRetries bounds the number of acquisition attempts after the
	// initial try. Total attempts = MaxRetries + 1.
	MaxRetries int
	// MaxElapsed bounds the total wall-clock time spent retrying. If both
	// MaxRetries and MaxElapsed are set, the first to trip wins.
	MaxElapsed time.Duration
}

// DefaultLockRetryPolicy returns the policy used by withTrackerLock. The
// curve is intentionally tight (sub-second) for in-process tracker-commit
// contention; the larger 30s/90s/300s curve referenced by the auto-triage
// child of ddx-3c154349 lives one layer up, in cli/internal/triage —
// it consults ActionRetryWithBackoff and re-queues across drain passes,
// while this policy resolves contention within a single attempt.
func DefaultLockRetryPolicy() LockRetryPolicy {
	return LockRetryPolicy{
		InitialBackoff: 50 * time.Millisecond,
		MaxBackoff:     1 * time.Second,
		Multiplier:     2.0,
		MaxRetries:     200,
		MaxElapsed:     30 * time.Second,
	}
}

// step returns the backoff duration for retry index n (0-based: n=0 is the
// wait BEFORE the second acquisition attempt).
func (p LockRetryPolicy) step(n int) time.Duration {
	if p.InitialBackoff <= 0 {
		return 0
	}
	d := float64(p.InitialBackoff)
	m := p.Multiplier
	if m < 1 {
		m = 1
	}
	for i := 0; i < n; i++ {
		d *= m
		if p.MaxBackoff > 0 && d >= float64(p.MaxBackoff) {
			d = float64(p.MaxBackoff)
			break
		}
	}
	out := time.Duration(d)
	if p.MaxBackoff > 0 && out > p.MaxBackoff {
		out = p.MaxBackoff
	}
	return out
}

// trackerLockStaleAge is the age after which a held tracker lock is
// considered stale (owner crashed mid-commit) and may be forcibly broken.
var trackerLockStaleAge = 10 * time.Minute

// trackerLockPolicy is the active retry policy for withTrackerLock.
// Tests may swap this out via the exported helpers below.
var trackerLockPolicy = DefaultLockRetryPolicy()

// trackerLockPath returns the main-git lock directory for the given project
// root. The historical name remains because tests and older comments refer to
// the tracker lock, but the lock now protects all primary-checkout git writes:
// tracker commits, pre-dispatch checkpoint/ref updates, and landing.
//
// The lock target must be shared across linked worktrees for the same repo, so
// we prefer the primary DDx workspace when one exists instead of the caller's
// checkout-local .ddx directory.
func trackerLockPath(projectRoot string) string {
	return lockmetrics.SharedTrackerLockPath(projectRoot)
}

// withMainGitLock acquires the process-shared main-git lock for the
// given project root, runs fn, and releases the lock. The lock is a
// directory created via os.Mkdir (atomic across processes on POSIX and
// Windows) following the same pattern as cli/internal/bead/lock.go.
//
// section identifies the call site (e.g. "durable_audit", "pre_dispatch",
// "land") and is surfaced in TrackerLockSample.Section and in the lockmetrics
// operation label so slow holds can be attributed without reading source.
//
// Contention is handled per LockRetryPolicy: exponential backoff up to a
// bounded budget. Per TD-031 §8.5 the contention itself does not change
// bead status; on budget exhaustion the caller surfaces an ordinary
// execution_failed and triage decides next steps.
func withMainGitLock(projectRoot, section string, fn func() error) error {
	if projectRoot == "" {
		return fn()
	}
	return withTrackerLockPolicy(projectRoot, section, trackerLockPolicy, fn)
}

// WithMainGitLock exposes the process-shared main-git lock to sibling
// packages that need the same serialized add/commit boundary as execute-bead
// landing and pre-dispatch checkpointing.
func WithMainGitLock(projectRoot, section string, fn func() error) error {
	return withMainGitLock(projectRoot, section, fn)
}

// withTrackerLock is retained for existing tracker/pre-dispatch call sites. It
// uses the same process-shared lock as landing so separate ddx work processes
// cannot interleave commits, ref updates, and checkout sync in the main tree.
func withTrackerLock(projectRoot, section string, fn func() error) error {
	return withMainGitLock(projectRoot, section, fn)
}

// TrackerLockSample carries timing and contention metrics for one
// withTrackerLock / withMainGitLock acquire+release cycle.
type TrackerLockSample struct {
	LockDir string
	Section string        // call-site identifier, e.g. "durable_audit", "pre_dispatch", "land"
	Wait    time.Duration // time from entry to lock acquisition
	Hold    time.Duration // time the callback held the lock
	Retries int           // number of sleep-and-retry iterations (0 = acquired on first try)
}

var (
	trackerLockSinkMu sync.RWMutex
	trackerLockSinkFn func(TrackerLockSample)
)

// TrackerLockTimeoutError marks a tracker-lock acquisition timeout so callers
// can classify it with errors.Is even when the error is wrapped several times.
type TrackerLockTimeoutError struct {
	Why      string
	LockDir  string
	OwnerPID string
}

// TrackerLockTimeoutErr is the sentinel used by errors.Is for transient
// tracker-lock contention.
var TrackerLockTimeoutErr = &TrackerLockTimeoutError{}

func (e *TrackerLockTimeoutError) Error() string {
	if e == nil {
		return "tracker lock timeout"
	}
	why := strings.TrimSpace(e.Why)
	if why == "" {
		why = "unknown"
	}
	lockDir := strings.TrimSpace(e.LockDir)
	if lockDir == "" {
		lockDir = "unknown"
	}
	owner := strings.TrimSpace(e.OwnerPID)
	if owner == "" {
		owner = "missing"
	}
	return fmt.Sprintf("tracker lock timeout (%s, lock: %s, owner pid: %s)", why, lockDir, owner)
}

func (e *TrackerLockTimeoutError) Is(target error) bool {
	_, ok := target.(*TrackerLockTimeoutError)
	return ok
}

// SetTrackerLockMetricsSink atomically installs a new tracker-lock
// metrics sink and returns the previous one. Passing nil disables
// emission. Safe for concurrent use; two workers in the same process
// will not race on the sink variable.
func SetTrackerLockMetricsSink(fn func(TrackerLockSample)) func(TrackerLockSample) {
	trackerLockSinkMu.Lock()
	prev := trackerLockSinkFn
	trackerLockSinkFn = fn
	trackerLockSinkMu.Unlock()
	return prev
}

// trackerLockContendedAttemptHook is a test-only hook fired after each
// failed acquire attempt that has been classified as real lock contention
// (a directory exists at lockDir and the stale-owner path did not reclaim
// it). It is invoked just before the retry sleep with the zero-based
// attempt index. The zero value (nil) is a no-op.
//
// Tests use this hook to deterministically synchronise with the retry
// loop — e.g. release the held lock from the hook so the next attempt
// observes a non-zero retry count without relying on time.Sleep races.
var trackerLockContendedAttemptHook func(attempt int)

// withTrackerLockPolicy is the policy-parameterised form of
// withTrackerLock; exposed at package scope so tests can pin a specific
// curve. section is the call-site identifier forwarded to TrackerLockSample
// and the lockmetrics operation label.
func withTrackerLockPolicy(projectRoot, section string, policy LockRetryPolicy, fn func() error) error {
	lockDir := trackerLockPath(projectRoot)
	if err := os.MkdirAll(filepath.Dir(lockDir), 0o755); err != nil {
		return fmt.Errorf("tracker lock dir: %w", err)
	}

package agent

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"sync"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// These tests pin the lock-scoping contract for ddx-329a08b8: the parent-repo
// git index lock (.git/index.lock) and the DDx tracker lock
// (.ddx/.git-tracker.lock) are acquired only for the brief git/tracker
// mutation windows (pre-dispatch checkpoint + post-subprocess commit/audit),
// never across the multi-minute LLM harness subprocess wait. Holding either
// lock across the subprocess (the original 2026-05-17 regression) blocks
// concurrent bead create/update/close with "tracker lock timeout" errors.

// lockScopeProbeRunner stands in for the LLM harness subprocess. While
// "running" it polls the parent-repo index lock and the DDx tracker lock to
// record whether either is held across the subprocess wait, and writes a
// tracked file into the worktree so the post-subprocess SynthesizeCommit
// performs a real git stage/commit.
type lockScopeProbeRunner struct {
	projectRoot string
	pollWindow  time.Duration

	mu              sync.Mutex
	subprocessStart time.Time
	subprocessEnd   time.Time
	indexLockHeld   bool
	trackerLockHeld bool
	polls           int
}

func (r *lockScopeProbeRunner) Run(opts RunArgs) (*Result, error) {
	indexLock := filepath.Join(r.projectRoot, ".git", "index.lock")
	trackerLock := ddxroot.JoinProject(r.projectRoot, ".git-tracker.lock")

	start := time.Now()
	r.mu.Lock()
	r.subprocessStart = start
	r.mu.Unlock()

	// Produce a real worktree change so the post-subprocess git stage/commit
	// (SynthesizeCommit) has tracked content to commit.
	if opts.WorkDir != "" {
		_ = os.WriteFile(filepath.Join(opts.WorkDir, "agent-change.txt"), []byte("change\n"), 0o644)
	}

	deadline := start.Add(r.pollWindow)
	for {
		now := time.Now()
		// index.lock counts as held-across-subprocess only when it exists with
		// an mtime at or after the subprocess started; a pre-existing lock with
		// an older mtime is permitted by the acceptance contract.
		if info, err := os.Stat(indexLock); err == nil && !info.ModTime().Before(start) {
			r.mu.Lock()
			r.indexLockHeld = true
			r.mu.Unlock()
		}
		// The tracker lock is a DDx-managed directory created only around a
		// mutation, so any presence during the subprocess means it spans the wait.
		if _, err := os.Stat(trackerLock); err == nil {
			r.mu.Lock()
			r.trackerLockHeld = true
			r.mu.Unlock()
		}
		r.mu.Lock()
		r.polls++
		r.mu.Unlock()
		if !now.Before(deadline) {
			break
		}
		time.Sleep(2 * time.Millisecond)
	}

	r.mu.Lock()
	r.subprocessEnd = time.Now()
	r.mu.Unlock()
	return &Result{ExitCode: 0}, nil
}

// lockSample records one tracker-lock acquire+release cycle observed via the
// TrackerLockMetricsSink seam, with the wall-clock release time so tests can
// place the acquisition relative to the subprocess window.
type lockSample struct {
	sample     TrackerLockSample
	releasedAt time.Time
}

type lockSampleRecorder struct {
	mu      sync.Mutex
	samples []lockSample
}

func (rec *lockSampleRecorder) record(s TrackerLockSample) {
	rec.mu.Lock()
	defer rec.mu.Unlock()
	rec.samples = append(rec.samples, lockSample{sample: s, releasedAt: time.Now()})
}

func (rec *lockSampleRecorder) snapshot() []lockSample {
	rec.mu.Lock()
	defer rec.mu.Unlock()
	out := make([]lockSample, len(rec.samples))
	copy(out, rec.samples)
	return out
}

// runLockScopeProbe drives a real ExecuteBeadWithConfig attempt against a real
// git repo with the worktree backend and a lockScopeProbeRunner subprocess,
// capturing tracker-lock acquisitions through the metrics sink. It returns the
// probe, the recorder, the result, and the project root.
func runLockScopeProbe(t *testing.T) (*lockScopeProbeRunner, *lockSampleRecorder, *ExecuteBeadResult, string) {
	t.Helper()

	projectRoot, _ := newScriptHarnessRepo(t, 1)
	const beadID = "ddx-int-0001"

	// Enable worktree-scoped config before any worktree is added so the
	// execute-bead git-isolation step (which sets --worktree config) succeeds.
	runGitInteg(t, projectRoot, "config", "extensions.worktreeConfig", "true")

	// Seed durable DDx bookkeeping dirt so the locked pre-dispatch sequence has
	// a real tracker/checkpoint commit to make. This makes the lock genuinely
	// guard a git index mutation, so "not held across the subprocess" is a
	// meaningful assertion rather than a vacuous one.
	metricsPath := filepath.Join(projectRoot, ddxroot.DirName, "metrics", "attempts.jsonl")
	require.NoError(t, os.MkdirAll(filepath.Dir(metricsPath), 0o755))
	require.NoError(t, os.WriteFile(metricsPath, []byte(`{"seed":"lock-scope"}`+"\n"), 0o644))

	rec := &lockSampleRecorder{}
	prevSink := SetTrackerLockMetricsSink(rec.record)
	t.Cleanup(func() { SetTrackerLockMetricsSink(prevSink) })

	runner := &lockScopeProbeRunner{projectRoot: projectRoot, pollWindow: 200 * time.Millisecond}
	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{}).Resolve(config.CLIOverrides{})

	res, err := ExecuteBeadWithConfig(context.Background(), projectRoot, beadID, rcfg,
		ExecuteBeadRuntime{AgentRunner: runner}, &RealGitOps{})
	require.NoError(t, err)
	require.NotNil(t, res)

	return runner, rec, res, projectRoot
}

// TestExecuteBead_IndexLockNotHeldAcrossSubprocess asserts that .git/index.lock
// is not freshly held for the duration of the harness subprocess wait.
func TestExecuteBead_IndexLockNotHeldAcrossSubprocess(t *testing.T) {
	runner, _, res, _ := runLockScopeProbe(t)

	runner.mu.Lock()
	indexHeld := runner.indexLockHeld
	polls := runner.polls
	runner.mu.Unlock()

	require.Greater(t, polls, 1, "probe must poll across the subprocess window")
	assert.NotEmpty(t, res.AttemptID, "run must have dispatched the subprocess")
	assert.False(t, indexHeld,
		".git/index.lock was held (mtime at/after subprocess start) during the harness subprocess wait")
}

// TestExecuteBead_TrackerLockNotHeldAcrossSubprocess asserts the same property
// for .ddx/.git-tracker.lock.
func TestExecuteBead_TrackerLockNotHeldAcrossSubprocess(t *testing.T) {
	runner, rec, _, _ := runLockScopeProbe(t)

	runner.mu.Lock()
	trackerHeld := runner.trackerLockHeld
	polls := runner.polls
	runner.mu.Unlock()

	require.Greater(t, polls, 1, "probe must poll across the subprocess window")
	assert.False(t, trackerHeld,
		".ddx/.git-tracker.lock was held during the harness subprocess wait")
	// Non-vacuity: the tracker lock IS exercised at least once (pre-dispatch
	// mutation), so its absence during the subprocess is a meaningful signal
	// rather than the lock never being used.
	assert.NotEmpty(t, rec.snapshot(),
		"tracker lock was never acquired; absence-during-subprocess would be vacuous")
}

// TestExecuteBead_LocksReacquiredForMutation asserts the locks ARE acquired
// (briefly) for the post-subprocess git stage/commit and tracker update, and
// that no acquisition straddles the subprocess wait window.
func TestExecuteBead_LocksReacquiredForMutation(t *testing.T) {
	runner, rec, res, projectRoot := runLockScopeProbe(t)

	// Post-subprocess git stage/commit: the worktree change written by the probe
	// was committed by SynthesizeCommit after the subprocess returned.
	assert.NotEqual(t, res.BaseRev, res.ResultRev,
		"post-subprocess git stage/commit did not advance the worktree HEAD")

	// Post-subprocess tracker update: the durable-audit commit re-acquires the
	// tracker lock (the same path FinalizeDurableAttemptAudit uses).
	require.NoError(t, CommitDurableAuditOutputs(projectRoot, res.AttemptID))

	samples := rec.snapshot()
	require.NotEmpty(t, samples, "tracker lock was never acquired for mutation")

	runner.mu.Lock()
	subStart := runner.subprocessStart
	subEnd := runner.subprocessEnd
	runner.mu.Unlock()
	require.False(t, subStart.IsZero(), "subprocess start not recorded")
	require.False(t, subEnd.IsZero(), "subprocess end not recorded")

	postSubprocess := 0
	for i, s := range samples {
		acquiredAt := s.releasedAt.Add(-s.sample.Hold)
		// No acquisition may straddle the subprocess wait: the lock is released
		// before the subprocess starts and (re)acquired only after it returns.
		spans := !acquiredAt.After(subStart) && !s.releasedAt.Before(subEnd)
		assert.Falsef(t, spans,
			"tracker lock acquisition #%d straddles the subprocess wait (acquired=%s released=%s sub=[%s,%s])",
			i, acquiredAt, s.releasedAt, subStart, subEnd)
		if acquiredAt.After(subEnd) {
			postSubprocess++
		}
	}
	assert.Positive(t, postSubprocess,
		"expected at least one tracker-lock acquisition for the post-subprocess mutation")
}

type signalPrepareBackend struct {
	inner   AttemptBackend
	started chan struct{}
	release <-chan struct{}
	once    sync.Once
}

func (b *signalPrepareBackend) Name() string { return b.inner.Name() }

func (b *signalPrepareBackend) Prepare(ctx context.Context, req AttemptBackendPrepareRequest) (*AttemptWorkspace, error) {
	if b.started != nil {
		b.once.Do(func() { close(b.started) })
	}
	if b.release != nil {
		<-b.release
	}
	return b.inner.Prepare(ctx, req)
}

func (b *signalPrepareBackend) Run(ctx context.Context, req AttemptBackendRunRequest) (*Result, error) {
	return b.inner.Run(ctx, req)
}

func (b *signalPrepareBackend) PublishResult(ctx context.Context, ws *AttemptWorkspace, res *ExecuteBeadResult) error {
	return b.inner.PublishResult(ctx, ws, res)
}

package git

import (
	"context"
	"os"
	"path/filepath"
	"strings"
	"time"
)

const ddxDirSegment = ".ddx"

// FindProjectRoot walks up from startDir to find the git repository root.
// It returns the top-level directory of the git working tree. If startDir
// is not inside a git repository, it returns startDir unchanged.
//
// This is analogous to `git rev-parse --show-toplevel` and ensures that
// ddx always operates from the repository root regardless of the caller's
// working directory. Without this, running `ddx` from a subdirectory that
// contains its own `.ddx/` folder would silently use the wrong workspace.
func FindProjectRoot(startDir string) string {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	cmd := Command(ctx, startDir, "rev-parse", "--show-toplevel")
	out, err := cmd.Output()
	if err != nil {
		// Not in a git repo — fall back to the original directory.
		return startDir
	}
	root := strings.TrimSpace(string(out))
	if root == "" {
		return startDir
	}
	if physical := physicalGitRoot(startDir); physical != "" && !samePath(physical, root) {
		return physical
	}
	return root
}

// physicalGitRoot walks upward on disk until it finds a .git directory or
// linked-worktree .git file. This intentionally bypasses git's configured
// worktree resolution so a corrupted local core.worktree cannot redirect ddx
// away from the checkout the operator actually invoked.
func physicalGitRoot(startDir string) string {
	current, err := filepath.Abs(startDir)
	if err != nil {
		return ""
	}
	for {
		if _, statErr := os.Stat(filepath.Join(current, ".git")); statErr == nil {
			return current
		}
		parent := filepath.Dir(current)
		if parent == current {
			return ""
		}
		current = parent
	}
}

func samePath(a, b string) bool {
	if a == "" || b == "" {
		return false
	}
	cleanA, err := filepath.Abs(a)
	if err != nil {
		cleanA = filepath.Clean(a)
	}
	cleanB, err := filepath.Abs(b)
	if err != nil {
		cleanB = filepath.Clean(b)
	}
	if resolvedA, err := filepath.EvalSymlinks(cleanA); err == nil {
		cleanA = resolvedA
	}
	if resolvedB, err := filepath.EvalSymlinks(cleanB); err == nil {
		cleanB = resolvedB
	}
	return cleanA == cleanB
}

// FindNearestDDxWorkspace walks up from startDir to find the nearest ancestor
// inside the current git repository that contains a .ddx workspace.
//
// When startDir is inside a linked git worktree (e.g. an execute-bead
// isolated worktree under .ddx/.execute-bead-wt-* or a worktrunk sibling
// like repo.feature-branch/), it resolves to the PRIMARY worktree's .ddx/
// first, not the linked worktree's own .ddx/. This is critical because:
//
//   - bead store mutations must land in the canonical project bead queue,
//     not in an isolated worktree's private snapshot that will be discarded
//   - the primary worktree is the operator's source of truth; linked
//     worktrees are ephemeral execution contexts
//
// If no in-tree .ddx/ exists, it falls back to the canonical project root so
// callers can still route project state through ddxroot.Path for convention-
// root projects.
//
// Returns an empty string only when startDir is not inside a git repository
// and no ancestor contains .ddx/.
func FindNearestDDxWorkspace(startDir string) string {
	abs, err := filepath.Abs(startDir)
	if err != nil {
		return ""
	}

	// If we're inside a linked worktree, prefer the primary worktree's .ddx/.
	if primary := primaryWorktreeRoot(abs); primary != "" && primary != FindProjectRoot(abs) {
		return primary
	}

	gitRoot := FindProjectRoot(abs)
	current := abs
	for {
		candidate := filepath.Join(current, ddxDirSegment)
		if info, statErr := os.Stat(candidate); statErr == nil && info.IsDir() {
			return current
		}
		if current == gitRoot {
			break
		}
		parent := filepath.Dir(current)
		if parent == current {
			break
		}
		current = parent
	}

	if IsRepository(abs) {
		return gitRoot
	}
	return ""
}

// IsRepository checks if the current directory is a git repository.
func IsRepository(path string) bool {
	if path == "" {
		path = "."
	}

	cleanPath := filepath.Clean(path)
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	cmd := Command(ctx, cleanPath, "rev-parse", "--git-dir")
	return cmd.Run() == nil
}

// primaryWorktreeRoot returns the primary (non-linked) worktree directory
// for a given path inside a git repository, or "" if the path is not inside
// a linked worktree (or if resolution fails).
//
// Detection: `git rev-parse --git-common-dir` returns the shared .git
// directory. If that differs from `git rev-parse --git-dir`, we're in a
// linked worktree. The primary worktree is the parent directory of the
// common .git dir (unless the shared dir is a bare repo).
func primaryWorktreeRoot(startDir string) string {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	gitDirCmd := Command(ctx, startDir, "rev-parse", "--path-format=absolute", "--git-dir")
	gitDirOut, err := gitDirCmd.Output()
	if err != nil {
		return ""
	}
	gitDir := strings.TrimSpace(string(gitDirOut))

	commonDirCmd := Command(ctx, startDir, "rev-parse", "--path-format=absolute", "--git-common-dir")
	commonDirOut, err := commonDirCmd.Output()
	if err != nil {
		return ""
	}
	commonDir := strings.TrimSpace(string(commonDirOut))

	if gitDir == commonDir {
		// Not a linked worktree.
		return ""
	}

	// Common dir is either a bare repo or the primary worktree's .git dir.
	// If it's a .git directory, the primary worktree is its parent.
	if filepath.Base(commonDir) == ".git" {
		return filepath.Dir(commonDir)
	}
	// Bare repo: no primary worktree. Caller falls back to walk-up.
	return ""
}

// Package lockmetrics emits structured acquire/release events for the
// process-shared locks DDx workers hold around git index and tracker
// mutations (.git/index.lock and .ddx/.git-tracker.lock). Each held critical
// section produces two JSON-line events — one "acquire" and one "release" —
// so operators can see how long a worker held a lock and which operation held
// it, instead of inferring from filesystem mtimes and ps output.
//
// Events are routed through a process-wide sink. The default sink is nil
// (a no-op): instrumentation at the lock seams is therefore zero-cost unless
// an entrypoint enables a sink. The `ddx work` and `ddx run` commands enable
// the file sink so lock activity for a run is captured at
// .ddx/metrics/locks.jsonl, where it can be read back via Load.
package lockmetrics

import (
	"bufio"
	"encoding/json"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
)

const (
	// MaxActiveSizeBytes is the maximum size of the active locks.jsonl before
	// it is rotated to a timestamped archive. Set to 4 MiB so the file stays
	// safely below the 5 MiB pre-commit large-file guard (lefthook.yml).
	MaxActiveSizeBytes = 4 * 1024 * 1024

	// MaxRotatedArchives is the number of timestamped archives retained
	// alongside the active file. Archives beyond this count are pruned oldest-first.
	MaxRotatedArchives = 3
)

// Event is one lock lifecycle event. An acquire event carries the
// acquisition-time fields; the matching release event additionally carries
// ReleasedAt and DurationMS so the held window is fully described. A
// "violation" event is emitted when a hold exceeds its configured cap (see
// InstrumentCapped) and carries Severity "error" and CapMS.
type Event struct {
	// Event is "acquire", "release", or "violation".
	Event string `json:"event"`
	// LockName identifies the lock, e.g. "index.lock" or "tracker.lock".
	LockName string `json:"lock_name"`
	// Operation labels the work that held the lock, e.g. "tracker.commit"
	// or "index.commit".
	Operation string `json:"operation"`
	// HolderPID is the pid of the process that held the lock.
	HolderPID int `json:"holder_pid"`
	// AcquiredAt is the RFC3339Nano timestamp the lock was acquired.
	AcquiredAt string `json:"acquired_at"`
	// ReleasedAt is the RFC3339Nano timestamp the lock was released.
	// Empty on the acquire event.
	ReleasedAt string `json:"released_at,omitempty"`
	// DurationMS is the held duration in milliseconds. On a release event it
	// is ReleasedAt minus AcquiredAt; on a violation event it is the hold so
	// far at the moment the cap tripped. Zero on the acquire event.
	DurationMS int64 `json:"duration_ms,omitempty"`
	// Severity is "error" on a "violation" event; empty otherwise.
	Severity string `json:"severity,omitempty"`
	// CapMS is the configured hold-time cap in milliseconds. Set only on a
	// "violation" event.
	CapMS int64 `json:"cap_ms,omitempty"`
}

var (
	sinkMu sync.RWMutex
	sink   func(Event)
)

// SetSink installs the process-wide event sink. Passing nil disables event
// emission (the default). Safe for concurrent use.
func SetSink(fn func(Event)) {
	sinkMu.Lock()
	sink = fn
	sinkMu.Unlock()
}

// Emit routes ev to the current sink if one is installed; otherwise it is a
// no-op. Safe for concurrent use.
func Emit(ev Event) {
	sinkMu.RLock()
	fn := sink
	sinkMu.RUnlock()
	if fn != nil {
		fn(ev)
	}
}

// Instrument records the held window of an already-acquired lock: it emits an
// "acquire" event, runs critical, then emits a matching "release" event with
// the measured hold duration. The holder pid is the current process. The
// release event is emitted even if critical panics. critical's error is
// returned unchanged.
//
// When process-wide cap enforcement is enabled (see SetCapEnforcement),
// Instrument additionally arms a hold-time cap for the lock; otherwise it is a
// pure metric wrapper.
func Instrument(lockName, operation string, critical func() error) error {
	return InstrumentCapped(lockName, operation, resolveCapConfig(lockName), critical)
}

// Path returns the absolute path to the lock-events stream under the project's
// DDx state root: .ddx/metrics/locks.jsonl.
func Path(projectRoot string) string {
	return ddxroot.JoinProject(projectRoot, "metrics", "locks.jsonl")
}

// FileSink returns a sink that appends each event as one JSON line to
// Path(projectRoot). Appends are serialized with O_APPEND and an internal
// mutex so concurrent workers in one process do not interleave partial lines.
// Write errors are best-effort and discarded — observability must never break
// the operation being observed.
func FileSink(projectRoot string) func(Event) {
	path := Path(projectRoot)
	var mu sync.Mutex
	return func(ev Event) {
		mu.Lock()
		defer mu.Unlock()
		_ = appendEvent(path, ev)
	}
}

func appendEvent(path string, ev Event) error {
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return err
	}
	if fi, err := os.Stat(path); err == nil && fi.Size() >= MaxActiveSizeBytes {
		_ = rotateLockMetrics(path)
	}
	f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644)
	if err != nil {
		return err
	}
	defer f.Close() //nolint:errcheck
	data, err := json.Marshal(ev)
	if err != nil {
		return err
	}
	data = append(data, '\n')
	_, err = f.Write(data)
	return err
}

// RotateIfNeeded renames path to a timestamped archive when its size is at or
// above MaxActiveSizeBytes, then prunes archives beyond MaxRotatedArchives.
// It is a no-op when the file does not exist or is within the size limit.
func RotateIfNeeded(path string) error {
	fi, err := os.Stat(path)
	if os.IsNotExist(err) || (err == nil && fi.Size() < MaxActiveSizeBytes) {
		return nil
	}
	if err != nil {
		return err
	}
	return rotateLockMetrics(path)
}

func rotateLockMetrics(path string) error {
	archive := path + "." + time.Now().UTC().Format("20060102T150405")
	if err := os.Rename(path, archive); err != nil {
		return err
	}
	return pruneOldArchives(path)
}

func pruneOldArchives(activePath string) error {
	dir := filepath.Dir(activePath)
	prefix := filepath.Base(activePath) + "."
	entries, err := os.ReadDir(dir)
	if err != nil {
		return err
	}
	var archives []string
	for _, e := range entries {
		if strings.HasPrefix(e.Name(), prefix) && !e.IsDir() {
			archives = append(archives, filepath.Join(dir, e.Name()))
		}
	}
	sort.Strings(archives)
	for len(archives) > MaxRotatedArchives {
		_ = os.Remove(archives[0])
		archives = archives[1:]
	}
	return nil
}

// Load reads all events from Path(projectRoot). Malformed lines are skipped.
// A missing file is not an error; it returns an empty slice.
func Load(projectRoot string) ([]Event, error) {
	f, err := os.Open(Path(projectRoot))
	if err != nil {
		if os.IsNotExist(err) {
			return []Event{}, nil
		}
		return nil, err
	}
	defer f.Close() //nolint:errcheck

	var events []Event
	sc := bufio.NewScanner(f)
	sc.Buffer(make([]byte, 64*1024), 1024*1024)
	for sc.Scan() {
		var ev Event
		if err := json.Unmarshal(sc.Bytes(), &ev); err != nil {
			continue
		}
		events = append(events, ev)
	}
	return events, sc.Err()
}

