// MarkResultExecutionError preserves a populated worker result as a structured
// attempt failure. Callers use this when ExecuteBeadWithConfig returned both a
// result and an error; the presence of the result means DDx has enough
// execution context to report the attempt instead of aborting the process.
func MarkResultExecutionError(res *ExecuteBeadResult, err error) {
	if res == nil || err == nil {
		return
	}
	if res.Outcome == "" {
		res.Outcome = ExecuteBeadOutcomeTaskFailed
	}
	if res.Reason == "" {
		res.Reason = err.Error()
	}
	if res.Error == "" {
		res.Error = err.Error()
	}
	if res.Status == "" || res.Status == ExecuteBeadStatusNoChanges {
		res.Status = ClassifyExecuteBeadStatus("error", res.ExitCode, res.Reason)
	}
	res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
	res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)
	if res.FailureMode == "" {
		res.FailureMode = FailureModeUnknown
	}
	// A pre-dispatch provider-boundary failure carries its typed classification
	// on the error (ddx-3b721804). Prefer it so the report's outcome_reason is
	// the precise provider taxonomy (provider_auth, provider_model_unavailable,
	// ...) rather than the coarse worker-level bucket.
	var pfErr *ProviderFailureError
	if errors.As(err, &pfErr) && pfErr.Failure.Reason != "" {
		res.FailureMode = pfErr.Failure.Reason
	}
}

// MarkResultLandError records a coordinator/landing failure on a completed
// worker result. When possible it first pins ResultRev under refs/ddx/iterations
// so the worker's commit remains reachable even though the target branch did
// not advance cleanly.
func MarkResultLandError(projectRoot string, res *ExecuteBeadResult, err error) {
	if res == nil || err == nil {
		return
	}
	if markReconciledAlreadyLanded(projectRoot, res, err) {
		return
	}
	reason := "land coordination failed: " + err.Error()
	if action, ok := classifyLandCoordinationAction(err.Error()); ok {
		switch action {
		case landCoordinationActionRetryLand:
			reason = "land coordination retry: " + err.Error()
			preserveResultRefForLandError(projectRoot, res, &reason)
			res.Outcome = "land_coordination_retry"
			res.Reason = reason
			res.Error = err.Error()
			res.Status = ExecuteBeadStatusLandRetry
			res.OrchestratorStatus = res.Status
			res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
			res.FailureMode = FailureModeLandRetry
			return
		case landCoordinationActionOperatorAttention:
			reason = "land coordination operator attention: " + err.Error()
			preserveResultRefForLandError(projectRoot, res, &reason)
			res.Outcome = "land_coordination_operator_attention"
			res.Reason = reason
			res.Error = err.Error()
			res.Status = ExecuteBeadStatusLandOperatorAttention
			res.OrchestratorStatus = res.Status
			res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
			res.FailureMode = FailureModeLandOperatorAttention
			return
		}
	}
	preserveResultRefForLandError(projectRoot, res, &reason)
	res.Outcome = "error"
	res.Reason = reason
	res.Error = err.Error()
	res.Status = ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
	res.OrchestratorStatus = res.Status
	res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
	res.FailureMode = classifyLandingFailureMode(res.Outcome, res.Reason, res.GateResults, res.FailureMode)
}

func preserveResultRefForLandError(projectRoot string, res *ExecuteBeadResult, reason *string) {
	if res == nil || res.ResultRev == "" || res.ResultRev == res.BaseRev {
		return
	}
	preserveRef := landIterationRef(res.BeadID, res.AttemptID, res.BaseRev)
	if upErr := (RealLandingGitOps{}).UpdateRefTo(projectRoot, preserveRef, res.ResultRev, ""); upErr == nil {
		res.PreserveRef = preserveRef
	} else if reason != nil {
		*reason = fmt.Sprintf("%s; preserving result failed: %v", *reason, upErr)
	}
}

type landCoordinationAction string

const (
	landCoordinationActionRetryLand         landCoordinationAction = "retry-land"
	landCoordinationActionOperatorAttention landCoordinationAction = "operator-attention"
)

func markReconciledAlreadyLanded(projectRoot string, res *ExecuteBeadResult, err error) bool {
	if projectRoot == "" || res == nil || res.ResultRev == "" || res.ResultRev == res.BaseRev || err == nil {
		return false
	}
	if !strings.Contains(strings.ToLower(err.Error()), "cannot lock ref") {
		return false
	}
	targets := landCoordinationTargetRefs(err.Error())
	targets = append(targets, "HEAD")
	for _, target := range targets {
		tip, ok := resultReachableFromRef(projectRoot, res.ResultRev, target)
		if !ok {
			continue
		}
		if res.ImplementationRev == "" {
			res.ImplementationRev = res.ResultRev
		}
		res.ResultRev = tip
		res.LandedRev = tip
		res.Outcome = "merged"
		res.Reason = "land coordination reconciled: result already landed"
		res.Error = err.Error()
		res.Status = ExecuteBeadStatusSuccess
		res.OrchestratorStatus = res.Status
		res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
		res.FailureMode = ""
		return true
	}
	return false
}

func resultReachableFromRef(projectRoot, resultRev, ref string) (string, bool) {
	tipOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", ref).Output()
	if err != nil {
		return "", false
	}
	tip := strings.TrimSpace(string(tipOut))
	if tip == "" {
		return "", false
	}
	err = internalgit.Command(context.Background(), projectRoot, "merge-base", "--is-ancestor", resultRev, tip).Run()
	return tip, err == nil
}

func landCoordinationTargetRefs(msg string) []string {
	var refs []string
	for _, token := range strings.FieldsFunc(msg, func(r rune) bool {
		return r == '\'' || r == '"' || r == ':' || r == ' ' || r == '\n' || r == '\t'
	}) {
		token = strings.TrimSpace(token)
		if strings.HasPrefix(token, "refs/heads/") {
			refs = append(refs, token)
		}
	}
	return refs
}

func classifyLandCoordinationAction(msg string) (landCoordinationAction, bool) {
	lower := strings.ToLower(msg)
	if strings.Contains(lower, "staged changes after waiting") {
		paths := stagedPathsFromLandError(msg)
		if len(paths) > 0 && allGeneratedLandCoordinationPaths(paths) {
			return landCoordinationActionRetryLand, true
		}
		return landCoordinationActionOperatorAttention, true
	}
	if strings.Contains(lower, "cannot lock ref") {
		return landCoordinationActionRetryLand, true
	}
	return "", false
}

func stagedPathsFromLandError(msg string) []string {
	lines := strings.Split(msg, "\n")
	if len(lines) <= 1 {
		return nil
	}
	var paths []string
	for _, line := range lines[1:] {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		if tab := strings.IndexByte(line, '\t'); tab >= 0 {
			line = line[tab+1:]
		}
		if p := strings.TrimSpace(line); p != "" {
			paths = append(paths, filepath.ToSlash(p))
		}
	}
	return paths
}

func allGeneratedLandCoordinationPaths(paths []string) bool {
	for _, p := range paths {
		if trackerpaths.IsManagedTrackerPath(p) ||
			strings.HasPrefix(p, ".ddx/executions/") ||
			strings.HasPrefix(p, ".ddx/runs/") ||
			strings.HasPrefix(p, ".ddx/metrics/") ||
			strings.HasPrefix(p, ".ddx/attachments/") {
			continue
		}
		return false
	}
	return true

		report.Status = ExecuteBeadStatusSuccess
		report.Detail = "dangling-success recovery: bead closed idempotently (result_rev already merged)"
	case danglingSuccessOutcomePreserved:
		report.Status = ExecuteBeadStatusPreservedNeedsReview
		report.Detail = "dangling-success: preserved successful result for operator landing"
	case danglingSuccessOutcomeOperatorRequired:
		report.Status = ExecuteBeadStatusExecutionFailed
		report.OutcomeReason = "operator_required"
		if recovery.FailureReason != "" {
			report.Detail = "dangling-success: successful result could not be landed automatically: " + recovery.FailureReason
		} else {
			report.Detail = "dangling-success: successful result could not be landed automatically"
		}
	default:
		report.Status = ExecuteBeadStatusExecutionFailed
		report.OutcomeReason = "operator_required"
		report.Detail = "dangling-success: unrecognized recovery outcome"
	}
	return report
}

const preExecuteCheckpointDirtyMarker = "pre-execute-bead checkpoint: " + preDispatchCheckpointDirtyRefusalPrefix

func preExecuteCheckpointDirtyStop(report ExecuteBeadReport, err error, projectRoot, beadID string) (*OperatorAttentionStop, bool) {
	detail := strings.TrimSpace(firstNonEmpty(report.Detail, report.Error))
	if err != nil && strings.Contains(err.Error(), preExecuteCheckpointDirtyMarker) {
		detail = strings.TrimSpace(err.Error())
	} else if !strings.Contains(detail, preExecuteCheckpointDirtyMarker) {
		return nil, false
	}
	paths := parsePreExecuteCheckpointDirtyPaths(detail)
	message := "commit or clean the listed implementation files before restarting ddx work"
	if len(paths) > 0 {
		message = fmt.Sprintf("commit or clean the listed implementation files before restarting ddx work: %s", strings.Join(paths, ", "))
	}
	return &OperatorAttentionStop{
		Reason:      "checkpoint_dirty",
		BeadID:      beadID,
		ProjectRoot: projectRoot,
		DirtyPaths:  paths,
		Message:     message,
	}, true
}

func parsePreExecuteCheckpointDirtyPaths(detail string) []string {
	idx := strings.Index(detail, preDispatchCheckpointDirtyRefusalPrefix)
	if idx == -1 {
		return nil
	}
	pathsField := detail[idx+len(preDispatchCheckpointDirtyRefusalPrefix):]
	if semi := strings.Index(pathsField, ";"); semi >= 0 {
		pathsField = pathsField[:semi]
	}
	var paths []string
	for _, path := range strings.Split(pathsField, ",") {
		path = strings.TrimSpace(path)
		if path != "" {
			paths = append(paths, path)
		}
	}
	return paths
}

func dirtyRootGuardStatePath(projectRoot string) string {
	return ddxroot.JoinProject(projectRoot, dirtyRootGuardStateFileName)
}

func existingDirtyRootGuardStatePath(projectRoot string) (string, bool) {
	return ddxroot.ExistingJoinProject(context.Background(), projectRoot, dirtyRootGuardStateFileName)
}

func readDirtyRootGuardState(projectRoot string) (*dirtyRootGuardState, error) {
	path, ok := existingDirtyRootGuardStatePath(projectRoot)
	if !ok {
		return nil, nil
	}
	raw, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}
	var state dirtyRootGuardState
	if err := json.Unmarshal(raw, &state); err != nil {
		return nil, err
	}
	return &state, nil
}

func writeDirtyRootGuardState(projectRoot string, state dirtyRootGuardState) error {
	path := dirtyRootGuardStatePath(projectRoot)
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return err
	}
	data, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		return err
	}
	data = append(data, '\n')
	tmp, err := os.CreateTemp(filepath.Dir(path), "dirty-root-guard-*.json.tmp")
	if err != nil {
		return err
	}
	tmpName := tmp.Name()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
		return err
	}
	if err := tmp.Close(); err != nil {
		_ = os.Remove(tmpName)
		return err
	}
	if err := os.Rename(tmpName, path); err != nil {
		_ = os.Remove(tmpName)
		return err
	}
	return nil
}

func clearDirtyRootGuardState(projectRoot string) error {
	path, ok := existingDirtyRootGuardStatePath(projectRoot)
	if !ok {
		return nil
	}
	if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
		return err
	}
	return nil
}

func normalizeDirtyRootPaths(paths []string) []string {
	if len(paths) == 0 {
		return nil
	}
	uniq := make(map[string]struct{}, len(paths))
	normalized := make([]string, 0, len(paths))
	for _, path := range paths {
		path = strings.TrimSpace(path)
		if path == "" {
			continue
		}
		if _, ok := uniq[path]; ok {
			continue
		}
		uniq[path] = struct{}{}
		normalized = append(normalized, path)
	}
	if len(normalized) == 0 {
		return nil
	}
	sort.Strings(normalized)
	return normalized
}

func dirtyRootPathFingerprint(paths []string) string {
	if len(paths) == 0 {
		return ""
	}
	return strings.Join(paths, "\x00")
}

func updateDirtyRootGuardState(projectRoot string, dirtyPaths []string, at time.Time, threshold int, cooldown time.Duration) (*dirtyRootGuardState, bool, error) {
	if projectRoot == "" {
		return nil, false, nil
	}
	if threshold <= 0 {
		threshold = DefaultDirtyRootEscalationThreshold
	}
	if cooldown <= 0 {
		cooldown = DirtyRootEscalationCooldown
	}
	paths := normalizeDirtyRootPaths(dirtyPaths)
	if len(paths) == 0 {
		if err := clearDirtyRootGuardState(projectRoot); err != nil {
			return nil, false, err
		}
		return nil, false, nil
	}
	fingerprint := dirtyRootPathFingerprint(paths)
	state, err := readDirtyRootGuardState(projectRoot)
	if err != nil {
		return nil, false, err
	}
	next := dirtyRootGuardState{
		Fingerprint:     fingerprint,
		DirtyPaths:      append([]string(nil), paths...),
		Count:           1,
		FirstObservedAt: at.UTC(),
		LastObservedAt:  at.UTC(),
	}
	if state != nil && state.Fingerprint == fingerprint {
		next.FirstObservedAt = state.FirstObservedAt
		if next.FirstObservedAt.IsZero() {
			next.FirstObservedAt = at.UTC()
		}
		next.Count = state.Count
		next.RetryAfter = state.RetryAfter
		if state.RetryAfter.After(at) {
			// The cooldown is still active. Preserve the existing marker so the
			// relaunch sees the same backoff instead of tightening the spin loop.
			next.Count = state.Count
			next.RetryAfter = state.RetryAfter
			if err := writeDirtyRootGuardState(projectRoot, next); err != nil {
				return nil, false, err
			}
			return &next, true, nil
		}
		next.Count = state.Count + 1
		if next.Count >= threshold {
			next.RetryAfter = at.UTC().Add(cooldown)
		} else {
			next.RetryAfter = time.Time{}
		}
	} else {
		next.Count = 1
		next.RetryAfter = time.Time{}
	}
	if next.Count >= threshold && next.RetryAfter.IsZero() {
		next.RetryAfter = at.UTC().Add(cooldown)
	}
	if err := writeDirtyRootGuardState(projectRoot, next); err != nil {
		return nil, false, err
	}
	return &next, next.Count >= threshold, nil
}

